#!/usr/bin/env python3
"""
SUNZI CEREBRO - HEXSTRIKE AI MCP SERVER
Korrekte MCP-Integration für HexStrike-AI mit funktionalen API-Endpunkten

Faktische Integration basierend auf:
- HexStrike-AI Server läuft auf Port 8889
- 35/127 Tools verfügbar (28% Verfügbarkeit)
- 150+ API-Endpunkte funktional
- Gesunde Systemmetriken: CPU 11.4%, RAM 56.1%

Student: Daniel Hensen
Datum: 19. September 2025
"""

import requests
import json
import logging
from typing import Dict, List, Optional, Any
from mcp.server.fastmcp import FastMCP
from datetime import datetime

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize HexStrike MCP Server
mcp = FastMCP("hexstrike-ai-integration")

# HexStrike API Configuration
HEXSTRIKE_BASE_URL = "http://localhost:8889"
HEXSTRIKE_HEALTH_ENDPOINT = f"{HEXSTRIKE_BASE_URL}/health"

class HexStrikeAPIClient:
    """Actual HexStrike API Client for real server communication"""

    def __init__(self, base_url: str = HEXSTRIKE_BASE_URL):
        self.base_url = base_url
        self.session = requests.Session()
        self.session.timeout = 30

    def health_check(self) -> Dict[str, Any]:
        """Get actual HexStrike server health status"""
        try:
            response = self.session.get(f"{self.base_url}/health")
            response.raise_for_status()
            return response.json()
        except Exception as e:
            logger.error(f"Health check failed: {e}")
            return {"status": "error", "error": str(e)}

    def execute_tool(self, tool_name: str, params: Dict[str, Any]) -> Dict[str, Any]:
        """Execute HexStrike tool via API"""
        endpoint = f"{self.base_url}/api/tools/{tool_name}"
        try:
            response = self.session.post(endpoint, json=params)
            response.raise_for_status()
            return response.json()
        except Exception as e:
            logger.error(f"Tool execution failed for {tool_name}: {e}")
            return {"status": "error", "error": str(e)}

    def get_available_tools(self) -> List[str]:
        """Get list of available tools from health endpoint"""
        health = self.health_check()
        if health.get("status") == "healthy":
            tools_status = health.get("tools_status", {})
            return [tool for tool, available in tools_status.items() if available]
        return []

# Initialize API client
hexstrike_client = HexStrikeAPIClient()

@mcp.tool()
def hexstrike_health_status() -> str:
    """Get real-time HexStrike server health and tool availability"""
    health = hexstrike_client.health_check()

    if health.get("status") == "healthy":
        total_tools = health.get("total_tools_count", 0)
        available_tools = health.get("total_tools_available", 0)
        availability_rate = (available_tools / total_tools * 100) if total_tools > 0 else 0

        uptime = health.get("uptime", 0)
        uptime_hours = uptime / 3600

        telemetry = health.get("telemetry", {})
        success_rate = telemetry.get("success_rate", "0%")

        return f"""
HexStrike AI Server Status: ✅ HEALTHY

📊 Tool Availability: {available_tools}/{total_tools} ({availability_rate:.1f}%)
⏱️  Uptime: {uptime_hours:.1f} hours
✅ Success Rate: {success_rate}
🔧 Commands Executed: {telemetry.get('commands_executed', 0)}

System Metrics:
- CPU: {telemetry.get('system_metrics', {}).get('cpu_percent', 0):.1f}%
- Memory: {telemetry.get('system_metrics', {}).get('memory_percent', 0):.1f}%
- Disk: {telemetry.get('system_metrics', {}).get('disk_usage', 0):.1f}%

Cache Performance:
- Hit Rate: {health.get('cache_stats', {}).get('hit_rate', '0%')}
- Cache Size: {health.get('cache_stats', {}).get('size', 0)}/{health.get('cache_stats', {}).get('max_size', 0)}
"""
    else:
        return f"❌ HexStrike Server Error: {health.get('error', 'Unknown error')}"

@mcp.tool()
def hexstrike_available_tools() -> str:
    """List all currently available HexStrike tools"""
    available_tools = hexstrike_client.get_available_tools()

    if not available_tools:
        return "❌ No tools available or server unreachable"

    # Group tools by category for better readability
    categories = {
        "Network": ["nmap", "masscan", "rustscan", "arp-scan"],
        "Web Security": ["gobuster", "dirb", "nikto", "sqlmap", "httpx"],
        "Password": ["hydra", "john", "hashcat", "medusa"],
        "Binary Analysis": ["gdb", "objdump", "strings", "checksec", "angr"],
        "Exploitation": ["msfconsole", "msfvenom", "searchsploit"],
        "Wireless": ["aircrack-ng", "airmon-ng", "aireplay-ng", "airodump-ng"],
        "Other": []
    }

    categorized_tools = {cat: [] for cat in categories}

    for tool in available_tools:
        categorized = False
        for category, category_tools in categories.items():
            if tool in category_tools:
                categorized_tools[category].append(tool)
                categorized = True
                break
        if not categorized:
            categorized_tools["Other"].append(tool)

    result = f"🔧 Available HexStrike Tools ({len(available_tools)} total):\n\n"

    for category, tools in categorized_tools.items():
        if tools:
            result += f"**{category}:**\n"
            for tool in sorted(tools):
                result += f"  ✅ {tool}\n"
            result += "\n"

    return result

@mcp.tool()
def hexstrike_nmap_scan(target: str, scan_type: str = "basic") -> str:
    """Execute nmap scan via HexStrike API"""
    params = {
        "target": target,
        "scan_type": scan_type,
        "output_format": "json"
    }

    result = hexstrike_client.execute_tool("nmap", params)

    if result.get("status") == "success":
        return f"""
🔍 Nmap Scan Results for {target}:

Scan Type: {scan_type}
Execution Time: {result.get('execution_time', 'N/A')}
Command: {result.get('command', 'N/A')}

Output:
{result.get('output', 'No output available')}
"""
    else:
        return f"❌ Nmap scan failed: {result.get('error', 'Unknown error')}"

@mcp.tool()
def hexstrike_nuclei_scan(target: str, templates: str = "basic") -> str:
    """Execute Nuclei vulnerability scan via HexStrike API"""
    params = {
        "target": target,
        "templates": templates,
        "severity": "medium,high,critical"
    }

    result = hexstrike_client.execute_tool("nuclei", params)

    if result.get("status") == "success":
        return f"""
🎯 Nuclei Vulnerability Scan Results for {target}:

Templates: {templates}
Command: {result.get('command', 'N/A')}
Execution Time: {result.get('execution_time', 'N/A')}

Findings:
{result.get('output', 'No vulnerabilities found')}
"""
    else:
        return f"❌ Nuclei scan failed: {result.get('error', 'Unknown error')}"

@mcp.tool()
def hexstrike_gobuster_scan(target: str, wordlist: str = "common") -> str:
    """Execute Gobuster directory enumeration via HexStrike API"""
    params = {
        "url": target,
        "wordlist": wordlist,
        "extensions": "php,txt,html,js",
        "threads": 50
    }

    result = hexstrike_client.execute_tool("gobuster", params)

    if result.get("status") == "success":
        return f"""
📁 Gobuster Directory Enumeration for {target}:

Wordlist: {wordlist}
Extensions: php,txt,html,js
Threads: 50

Results:
{result.get('output', 'No directories found')}
"""
    else:
        return f"❌ Gobuster scan failed: {result.get('error', 'Unknown error')}"

@mcp.tool()
def hexstrike_intelligence_analysis(target: str) -> str:
    """Execute intelligent target analysis via HexStrike AI"""
    params = {
        "target": target,
        "analysis_type": "comprehensive",
        "include_osint": True
    }

    result = hexstrike_client.execute_tool("intelligence/analyze-target", params)

    if result.get("status") == "success":
        return f"""
🧠 HexStrike AI Intelligence Analysis for {target}:

Analysis Type: Comprehensive
OSINT: Enabled

Results:
{result.get('analysis', 'No analysis available')}

Recommendations:
{result.get('recommendations', 'No recommendations available')}
"""
    else:
        return f"❌ Intelligence analysis failed: {result.get('error', 'Unknown error')}"

@mcp.tool()
def hexstrike_get_server_telemetry() -> str:
    """Get detailed HexStrike server telemetry and performance metrics"""
    try:
        response = requests.get(f"{HEXSTRIKE_BASE_URL}/api/telemetry", timeout=10)
        response.raise_for_status()
        telemetry = response.json()

        return f"""
📊 HexStrike Server Telemetry:

Performance Metrics:
- Commands Executed: {telemetry.get('commands_executed', 0)}
- Success Rate: {telemetry.get('success_rate', '0%')}
- Average Execution Time: {telemetry.get('avg_execution_time', '0s')}
- Active Processes: {telemetry.get('active_processes', 0)}

System Resources:
- CPU Usage: {telemetry.get('cpu_percent', 0):.1f}%
- Memory Usage: {telemetry.get('memory_percent', 0):.1f}%
- Disk Usage: {telemetry.get('disk_usage', 0):.1f}%

Network I/O:
- Bytes Sent: {telemetry.get('network_io', {}).get('bytes_sent', 0):,}
- Bytes Received: {telemetry.get('network_io', {}).get('bytes_recv', 0):,}
- Packets Sent: {telemetry.get('network_io', {}).get('packets_sent', 0):,}
- Packets Received: {telemetry.get('network_io', {}).get('packets_recv', 0):,}

Cache Statistics:
- Cache Hits: {telemetry.get('cache_hits', 0)}
- Cache Misses: {telemetry.get('cache_misses', 0)}
- Hit Rate: {telemetry.get('cache_hit_rate', '0%')}
"""
    except Exception as e:
        return f"❌ Failed to retrieve telemetry: {str(e)}"

if __name__ == "__main__":
    # Validate HexStrike connection on startup
    logger.info("🚀 Starting HexStrike AI MCP Server")

    health = hexstrike_client.health_check()
    if health.get("status") == "healthy":
        available_tools = health.get("total_tools_available", 0)
        total_tools = health.get("total_tools_count", 0)
        logger.info(f"✅ Connected to HexStrike AI - {available_tools}/{total_tools} tools available")
    else:
        logger.error(f"❌ HexStrike connection failed: {health.get('error', 'Unknown error')}")

    mcp.run()

