#!/usr/bin/env python3
"""
SUNZI CEREBRO - MULTICHAIN MCP SERVER
MCP Interface für das Multi-Chain Trigger System

Provides MCP tools for:
- Chain execution management
- Strategic tool orchestration
- Performance monitoring
- Custom chain creation

Student: Daniel Hensen
Datum: 19. September 2025
"""

import asyncio
import json
import logging
from typing import Dict, List, Optional, Any
from mcp.server.fastmcp import FastMCP
from sunzi_multichain_trigger_system import multichain_system, TriggerType, ToolCategory

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize MCP Server
mcp = FastMCP("sunzi-multichain-orchestrator")

@mcp.tool()
def get_available_chains() -> str:
    """List all available tool chains"""
    chains = multichain_system.chains

    result = "🎯 SUNZI CEREBRO - AVAILABLE TOOL CHAINS\n"
    result += "=" * 50 + "\n\n"

    for chain_id, chain in chains.items():
        result += f"📋 **{chain.name}**\n"
        result += f"   ID: {chain_id}\n"
        result += f"   Type: {chain.trigger_type.value}\n"
        result += f"   Tools: {len(chain.links)}\n"
        result += f"   Description: {chain.description}\n\n"

        # List tools in chain
        result += "   🔧 Tools:\n"
        for i, link in enumerate(chain.links, 1):
            result += f"      {i}. {link.tool_name} ({link.category.value})\n"
        result += "\n"

    return result

@mcp.tool()
async def execute_web_security_chain(target: str, scan_level: str = "standard") -> str:
    """Execute comprehensive web security assessment chain"""

    execution_params = {
        "scan_level": scan_level,
        "user_agent": "SunziCerebro/1.0"
    }

    try:
        execution_id = await multichain_system.execute_chain(
            "web_security_comprehensive",
            target,
            execution_params
        )

        return f"""
🎯 Web Security Chain Execution Started

Target: {target}
Execution ID: {execution_id}
Scan Level: {scan_level}

🔧 Chain Components:
1. HTTP Probing (httpx)
2. Vulnerability Scanning (nuclei)
3. Directory Enumeration (gobuster)
4. SQL Injection Testing (sqlmap)

⏱️ Estimated Duration: 10-30 minutes
📊 Use get_chain_status() to monitor progress
"""
    except Exception as e:
        return f"❌ Failed to start web security chain: {str(e)}"

@mcp.tool()
async def execute_network_reconnaissance(target: str, intensity: str = "normal") -> str:
    """Execute parallel network reconnaissance chain"""

    execution_params = {
        "intensity": intensity,
        "timing": 4 if intensity == "normal" else 5
    }

    try:
        execution_id = await multichain_system.execute_chain(
            "network_reconnaissance",
            target,
            execution_params
        )

        return f"""
🌐 Network Reconnaissance Chain Started

Target: {target}
Execution ID: {execution_id}
Intensity: {intensity}

🔧 Parallel Execution:
- Network Mapping (nmap)
- Fast Port Scanning (masscan)
- Subdomain Discovery (subfinder)

⚡ Execution Type: PARALLEL
📊 Use get_chain_status() to monitor progress
"""
    except Exception as e:
        return f"❌ Failed to start network reconnaissance: {str(e)}"

@mcp.tool()
async def execute_adaptive_intelligence(target: str, include_osint: bool = True) -> str:
    """Execute adaptive intelligence gathering chain"""

    execution_params = {
        "include_osint": include_osint,
        "analysis_depth": "comprehensive"
    }

    try:
        execution_id = await multichain_system.execute_chain(
            "adaptive_intelligence",
            target,
            execution_params
        )

        return f"""
🧠 Adaptive Intelligence Chain Started

Target: {target}
Execution ID: {execution_id}
OSINT: {'Enabled' if include_osint else 'Disabled'}

🔧 Adaptive Features:
- Initial Intelligence Analysis
- Dynamic Tool Selection
- Context-Aware Execution
- Feedback Loop Optimization

🚀 Execution Type: ADAPTIVE
📊 Use get_chain_status() to monitor progress
"""
    except Exception as e:
        return f"❌ Failed to start adaptive intelligence: {str(e)}"

@mcp.tool()
def get_chain_status(execution_id: str) -> str:
    """Get detailed status of chain execution"""
    status = multichain_system.get_chain_status(execution_id)

    if "error" in status:
        return f"❌ {status['error']}"

    status_emoji = {
        "running": "⏳",
        "completed": "✅",
        "failed": "❌",
        "partial": "🔄"
    }.get(status["status"], "❓")

    result = f"""
{status_emoji} CHAIN EXECUTION STATUS

Execution ID: {execution_id}
Chain ID: {status['chain_id']}
Status: {status['status'].upper()}
Start Time: {status['start_time']}
"""

    if status.get('end_time'):
        result += f"End Time: {status['end_time']}\n"

    result += f"Results Collected: {status['results_count']}\n"

    if status['errors']:
        result += f"\n❌ Errors:\n"
        for error in status['errors']:
            result += f"   - {error}\n"

    return result

@mcp.tool()
def get_system_status() -> str:
    """Get overall multi-chain system status and performance metrics"""
    status = multichain_system.get_system_status()

    return f"""
🎯 SUNZI CEREBRO - MULTI-CHAIN SYSTEM STATUS

System Status: {status['system_status'].upper()}
Available Chains: {status['available_chains']}
Active Executions: {status['active_executions']}
Total Executions: {status['total_executions']}
Queue Size: {status['queue_size']}

📊 PERFORMANCE METRICS:
- Chains Executed: {status['performance_metrics']['chains_executed']}
- Success Rate: {status['performance_metrics']['success_rate']:.1f}%
- Avg Execution Time: {status['performance_metrics']['average_execution_time']:.2f}s

🔧 AVAILABLE CHAIN TYPES:
- Web Security Comprehensive
- Network Reconnaissance
- Adaptive Intelligence

💡 Use get_available_chains() for detailed chain information
"""

@mcp.tool()
def create_custom_chain(chain_config: str) -> str:
    """Create custom tool chain from JSON configuration"""
    try:
        config = json.loads(chain_config)
        chain_id = multichain_system.create_custom_chain(config)

        return f"""
✅ Custom Chain Created Successfully

Chain ID: {chain_id}
Name: {config['name']}
Type: {config['trigger_type']}
Tools: {len(config['links'])}

The chain is now available for execution.
Use execute_custom_chain() to run it.
"""
    except json.JSONDecodeError:
        return "❌ Invalid JSON configuration"
    except Exception as e:
        return f"❌ Failed to create chain: {str(e)}"

@mcp.tool()
async def execute_custom_chain(chain_id: str, target: str, parameters: str = "{}") -> str:
    """Execute a custom tool chain"""
    try:
        params = json.loads(parameters)
        execution_id = await multichain_system.execute_chain(chain_id, target, params)

        return f"""
🚀 Custom Chain Execution Started

Chain ID: {chain_id}
Target: {target}
Execution ID: {execution_id}

📊 Use get_chain_status() to monitor progress
"""
    except json.JSONDecodeError:
        return "❌ Invalid parameters JSON"
    except Exception as e:
        return f"❌ Failed to execute custom chain: {str(e)}"

@mcp.tool()
def get_execution_history(limit: int = 10) -> str:
    """Get recent execution history"""
    executions = list(multichain_system.active_executions.values())
    executions.sort(key=lambda x: x.start_time, reverse=True)

    if not executions:
        return "📋 No execution history available"

    result = f"📋 RECENT EXECUTIONS (Last {min(limit, len(executions))})\n"
    result += "=" * 50 + "\n\n"

    for execution in executions[:limit]:
        status_emoji = {
            "running": "⏳",
            "completed": "✅",
            "failed": "❌",
            "partial": "🔄"
        }.get(execution.status, "❓")

        duration = ""
        if execution.end_time:
            duration = f"({(execution.end_time - execution.start_time).total_seconds():.1f}s)"

        result += f"{status_emoji} {execution.execution_id}\n"
        result += f"   Chain: {execution.chain_id}\n"
        result += f"   Status: {execution.status.upper()} {duration}\n"
        result += f"   Results: {len(execution.results)}\n"
        result += f"   Started: {execution.start_time.strftime('%H:%M:%S')}\n\n"

    return result

@mcp.tool()
def stop_execution(execution_id: str) -> str:
    """Stop a running chain execution"""
    if execution_id not in multichain_system.active_executions:
        return f"❌ Execution {execution_id} not found"

    execution = multichain_system.active_executions[execution_id]
    if execution.status != "running":
        return f"❌ Execution {execution_id} is not running (status: {execution.status})"

    # Note: In production, implement proper cancellation mechanism
    execution.status = "stopped"
    execution.errors.append("Manual stop requested")

    return f"🛑 Execution {execution_id} has been stopped"

if __name__ == "__main__":
    logger.info("🚀 Starting Sunzi Multi-Chain MCP Server")
    logger.info(f"📊 System status: {multichain_system.get_system_status()}")
    mcp.run()

